-- {"operators": "INNER_JOIN,AGGREGATE,FILTER,HAVING", "complexity": "high", "is_incremental": true, "has_nulls": true, "has_cast": false, "has_case": true, "tables": "WAREHOUSE,DISTRICT,CUSTOMER,OORDER,ORDER_LINE"}
SELECT w.W_ID, d.D_ID, c.C_CREDIT, SUM(ol.OL_AMOUNT) AS total_revenue, COUNT(*) AS line_count, SUM(CASE WHEN o.O_CARRIER_ID IS NULL THEN ol.OL_AMOUNT ELSE 0 END) AS unshipped_revenue, MAX(ol.OL_AMOUNT) AS largest_order_line FROM WAREHOUSE w JOIN DISTRICT d ON w.W_ID = d.D_W_ID JOIN CUSTOMER c ON d.D_W_ID = c.C_W_ID AND d.D_ID = c.C_D_ID JOIN OORDER o ON c.C_W_ID = o.O_W_ID AND c.C_D_ID = o.O_D_ID AND c.C_ID = o.O_C_ID JOIN ORDER_LINE ol ON o.O_W_ID = ol.OL_W_ID AND o.O_D_ID = ol.OL_D_ID AND o.O_ID = ol.OL_O_ID GROUP BY w.W_ID, d.D_ID, c.C_CREDIT HAVING SUM(ol.OL_AMOUNT) > 100 AND COUNT(*) > 1;
